1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life", () => {
5	  it("should return an empty set when there are no living cells", () => {
6	    expect(nextGeneration(new Set())).toEqual(new Set());
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration(new Set(["0,0"]))).toEqual(new Set());
10	  });
11	  it("should kill a live cell with only one live neighbor (underpopulation)", () => {
12	    expect(nextGeneration(new Set(["0,0", "1,0"]))).toEqual(new Set());
13	  });
14	  it("should keep a live cell alive with two live neighbors", () => {
15	    expect(nextGeneration(new Set(["0,0", "1,0", "-1,0"]))).toContain("0,0");
16	  });
17	  it("should keep a live cell alive with three live neighbors", () => {
18	    expect(nextGeneration(new Set(["0,0", "1,0", "-1,0", "0,1"]))).toContain("0,0");
19	  });
20	  it.todo("should kill a live cell with four live neighbors (overpopulation)");
21	  it.todo("should bring a dead cell to life when it has exactly three live neighbors (reproduction)");
22	  it.todo("should handle living cells at negative coordinates");
23	});
